import { useMemo, useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";

const FAQS = [
  { q: "How do currency exchange rates work?", a: "Exchange rates compare the value of one currency against another. They move based on interest rates, inflation, trade, economic growth, and market demand." },
  { q: "What is the strongest currency in the world?", a: "The strongest currency changes over time, but currencies such as the Kuwaiti dinar are often among the highest valued against the US dollar." },
  { q: "What is the difference between mid-market rate and bank rate?", a: "The mid-market rate is the midpoint between buy and sell prices. Banks and exchange services usually add a spread or fee, so their customer rate may be less favorable." },
  { q: "How often do exchange rates change?", a: "Major currency exchange rates can change constantly during market hours. For important transfers, always confirm the live rate with your bank or provider." },
  { q: "What is currency hedging?", a: "Currency hedging is a strategy used to reduce risk from exchange-rate changes, often through forward contracts or other financial instruments." },
];

const CURRENCIES = [
  { code: "USD", name: "US Dollar", flag: "", perUsd: 1 },
  { code: "EUR", name: "Euro", flag: "", perUsd: 0.92 },
  { code: "GBP", name: "British Pound", flag: "", perUsd: 0.79 },
  { code: "JPY", name: "Japanese Yen", flag: "", perUsd: 156 },
  { code: "CAD", name: "Canadian Dollar", flag: "", perUsd: 1.37 },
  { code: "AUD", name: "Australian Dollar", flag: "", perUsd: 1.51 },
  { code: "CHF", name: "Swiss Franc", flag: "", perUsd: 0.91 },
  { code: "CNY", name: "Chinese Yuan", flag: "^3", perUsd: 7.24 },
  { code: "INR", name: "Indian Rupee", flag: "^3", perUsd: 83.5 },
  { code: "PKR", name: "Pakistani Rupee", flag: "", perUsd: 278 },
  { code: "AED", name: "UAE Dirham", flag: "", perUsd: 3.67 },
  { code: "SAR", name: "Saudi Riyal", flag: "", perUsd: 3.75 },
  { code: "MXN", name: "Mexican Peso", flag: "^2", perUsd: 16.8 },
  { code: "BRL", name: "Brazilian Real", flag: "-", perUsd: 5.15 },
  { code: "KRW", name: "South Korean Won", flag: "-", perUsd: 1365 },
] as const;

type CurrencyCode = typeof CURRENCIES[number]["code"];
const byCode = Object.fromEntries(CURRENCIES.map((currency) => [currency.code, currency])) as Record<CurrencyCode, typeof CURRENCIES[number]>;

function convert(amount: number, from: CurrencyCode, to: CurrencyCode) {
  return amount / byCode[from].perUsd * byCode[to].perUsd;
}

function format(value: number, code: CurrencyCode) {
  return new Intl.NumberFormat("en-US", { style: "currency", currency: code, maximumFractionDigits: code === "JPY" || code === "KRW" ? 0 : 2 }).format(value);
}

export default function CurrencyCalculator() {
  const [amount, setAmount] = useState(100);
  const [from, setFrom] = useState<CurrencyCode>("USD");
  const [to, setTo] = useState<CurrencyCode>("EUR");
  const converted = convert(amount, from, to);
  const rate = convert(1, from, to);
  const reverseRate = convert(1, to, from);
  const comparisonRows = useMemo(() => CURRENCIES.map((currency) => ({ ...currency, value: convert(1, "USD", currency.code) })), []);
  const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";

  return (
    <>
      <SEOHead title="Free Currency Calculator Online - Convert Any Currency Instantly | CalcHive" description="Free online currency calculator. Convert between USD, EUR, GBP, JPY, INR, PKR and 15 plus major world currencies instantly. 100% free, no signup required." canonical="/currency-calculator" keywords="free currency calculator, currency converter free online, USD to EUR calculator free, exchange rate calculator free, money converter free online" category="Financial Calculators" breadcrumbName="Free Currency Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Currency Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Convert between major world currencies and compare one US dollar against all supported currencies.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-4 mb-8">
            <div><label className="text-sm font-semibold text-foreground block mb-2">Amount</label><input type="number" min="0" value={amount} onChange={(e) => setAmount(Number(e.target.value))} className={inputClass} /></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">From</label><select value={from} onChange={(e) => setFrom(e.target.value as CurrencyCode)} className={inputClass}>{CURRENCIES.map((currency) => <option key={currency.code} value={currency.code}>{currency.code} - {currency.name}</option>)}</select></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">To</label><select value={to} onChange={(e) => setTo(e.target.value as CurrencyCode)} className={inputClass}>{CURRENCIES.map((currency) => <option key={currency.code} value={currency.code}>{currency.code} - {currency.name}</option>)}</select></div>
          </div>
          <motion.div key={`${amount}-${from}-${to}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Converted Amount</p><p className="text-5xl sm:text-6xl font-black text-white tracking-tight" data-testid="result-currency">{format(converted, to)}</p></div>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground font-medium mb-1">Conversion rate</p><p className="text-lg font-extrabold text-foreground">1 {from} = {rate.toFixed(4)} {to}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground font-medium mb-1">Reverse conversion</p><p className="text-lg font-extrabold text-foreground">1 {to} = {reverseRate.toFixed(4)} {from}</p></div></div>
          </motion.div>
        </section>
        <ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Convert Any Currency for Free</h2><p className="text-muted-foreground leading-relaxed">Choose the starting currency, destination currency, and amount. This money converter free online applies the selected exchange rate and also shows the reverse rate.</p>
          <h2 className="text-2xl font-bold text-foreground">Major World Currency Exchange Rates</h2>
          <div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Currency Comparison - 1 USD Equals</caption><thead className="bg-muted/60"><tr>{["Currency", "Code", "Value", "Flag emoji"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{comparisonRows.map((row) => <tr key={row.code} className="hover:bg-muted/30"><td className="py-2.5 px-3 font-semibold text-foreground">{row.name}</td><td className="py-2.5 px-3">{row.code}</td><td className="py-2.5 px-3 text-sky-600 dark:text-sky-400 font-semibold">{row.value.toLocaleString(undefined, { maximumFractionDigits: 4 })}</td><td className="py-2.5 px-3">{row.flag}</td></tr>)}</tbody></table></div>
          <h2 className="text-2xl font-bold text-foreground">Free Money Currency Converter for Everyone</h2><p className="text-xs text-muted-foreground">Rates are reference values for calculator use and can differ from live bank or transfer-provider rates.</p>
        </section>

        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/currency-calculator" headingLevel="h3" />
      </main>
    </>
  );
}



